    def __init__(self):
        self.cache = {}

    def get_cache(self, index_file):
        if index_file not in self.cache:
            self.cache[index_file] = {}
        return self.cache[index_file]

    def set_cache(self, index_file, key, value):
        self.get_cache(index_file)[key] = value

    def delete_cache(self, index_file, key):
        if index_file in self.cache and key in self.cache[index_file]:
            del self.cache[index_file][key]

    def delete_index_cache(self, index_file):
        if index_file in self.cache:
            del self.cache[index_file]
